import json, tiktoken

def estimate_ft_cost(jsonl_path: str, model: str = "gpt-4o-mini-2024-07-18",
                     n_epochs: int = 3, cost_per_1m: float = 3.00) -> dict:
    enc = tiktoken.encoding_for_model("gpt-4o")  # same encoding family
    total = 0
    with open(jsonl_path) as f:
        for line in f:
            for msg in json.loads(line)["messages"]:
                total += len(enc.encode(msg.get("content", "")))
    training_tokens = total * n_epochs
    return {
        "total_tokens": total,
        "training_tokens": training_tokens,
        "estimated_cost_usd": round((training_tokens / 1_000_000) * cost_per_1m, 4),
    }
